choose.when:
SELECT cpi.*, task.ID_ AS task_id, task.NAME_ AS taskName, cu.nickname createByName FROM ACT_RU_TASK task INNER JOIN cat_process_instance cpi ON cpi.process_instance_id = task.PROC_INST_ID_ AND cpi.deleted = '0' INNER JOIN cat_user cu ON cpi.create_by = cu.id WHERE task.ASSIGNEE_ = #{param.userId}
AND ( cpi.title LIKE CONCAT('%', #{param.search}, '%') OR cpi.code LIKE CONCAT('%', #{param.search}, '%') )
AND cpi.process_definition_id = #{param.processDefinitionId}
ORDER BY task.CREATE_TIME_ DESC

SELECT cpi.*, hti.ID_ AS task_id, hti.NAME_ AS taskName, cu.nickname createByName
FROM ACT_HI_TASKINST hti
INNER JOIN cat_process_instance cpi
    ON cpi.process_instance_id = hti.PROC_INST_ID_ AND cpi.deleted = '0'
INNER JOIN cat_user cu ON cpi.create_by = cu.id
WHERE hti.ASSIGNEE_ = #{param.userId}
  AND hti.END_TIME_ IS NOT NULL

      AND hti.START_TIME_ >= #{param.startTime}


      AND hti.START_TIME_ <= #{param.endTime}


      AND hti.START_TIME_ >= DATE_SUB(NOW(), INTERVAL 6 MONTH)


    AND (
        cpi.title LIKE CONCAT('%', #{param.search}, '%')
        OR cpi.code LIKE CONCAT('%', #{param.search}, '%')
    )


    AND cpi.process_definition_id = #{param.processDefinitionId}


    AND cpi.process_status = #{param.processStatus}

ORDER BY hti.END_TIME_ DESC
